import { BaseDisplaySet } from './BaseDisplaySet';
function collectUnderlyingImageIds(instances) {
    const ids = [];
    for (const instance of instances) {
        if (instance.imageId) {
            ids.push(instance.imageId);
        }
    }
    return ids;
}
